import hashlib
from flask import Flask, request, Response
from prometheus_client import Counter, generate_latest, CONTENT_TYPE_LATEST, REGISTRY

app = Flask(__name__)
user_path_counters = {}

def get_metric_name(user_id, path):
    # Generate a valid metric name with a hash of the path to avoid illegal characters.
    digest = hashlib.md5(path.encode('utf-8')).hexdigest()
    # Metric names must match [a-zA-Z_:][a-zA-Z0-9_:]*
    return f"http_requests_{user_id}_{digest}"

def get_or_create_counter(user_id, path):
    key = (user_id, path)
    if key not in user_path_counters:
        metric_name = get_metric_name(user_id, path)
        # Create a Counter with label 'session_id'
        counter = Counter(metric_name, "HTTP requests", ['session_id'])
        user_path_counters[key] = counter
    return user_path_counters[key]

@app.before_request
def track_request():
    # Extract user_id and session_id from query parameters; use 'unknown' if not provided.
    user_id = request.args.get("user_id", "unknown")
    session_id = request.args.get("session_id", "unknown")
    # Use full request path (excluding query parameters) for metric segmentation.
    path = request.path
    counter = get_or_create_counter(user_id, path)
    counter.labels(session_id=session_id).inc()

@app.route("/")
def index():
    return "Hello, World!"

@app.route("/metrics")
def metrics():
    return Response(generate_latest(REGISTRY), mimetype=CONTENT_TYPE_LATEST)

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=8000)